+function getProtectedLines(lines: string[]): Set<number> {
+  const protectedLines = new Set<number>();
+  let inYaml = lines[0]?.trim() === '---';
+  let fence: {character: string, length: number} | null = null;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      protectedLines.add(index);
+      if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+      continue;
+    }
+    if (fence) {
+      protectedLines.add(index);
+      if (new RegExp(`^ {0,3}${fence.character}{${fence.length},}\\\\s*$`).test(line)) fence = null;
+      continue;
+    }
+    if (inMath) {
+      protectedLines.add(index);
+      if (/^\\s*(\\$\\$+|\\\\\\])\\s*$/.test(line)) inMath = false;
+      continue;
+    }
+
+    const fenceMatch = line.match(/^ {0,3}(`{3,}|~{3,})/);
+    if (fenceMatch) {
+      protectedLines.add(index);
+      fence = {character: fenceMatch[1][0], length: fenceMatch[1].length};
+    } else if (/^\\s*(\\$\\$+|\\\\\\[)\\s*$/.test(line)) {
+      protectedLines.add(index);
+      inMath = true;
+    }
+  }
+  return protectedLines;
+}
+
+function getHeadings(lines: string[], protectedLines: Set<number>, tocStartLine: number, tocEndLine: number): Heading[] {
+  const headings: Heading[] = [];
+  for (let index = 0; index < lines.length; index++) {
+    if (protectedLines.has(index) || (index >= tocStartLine && index <= tocEndLine)) continue;
+    const match = lines[index].match(atxHeading);
+    if (match) headings.push({level: match[1].length, text: match[2] ?? '', line: index});
+  }
+  return headings;
+}
+
+function getTocItems(headings: Heading[], options: AutoTocOptions): string[] {
+  const anchors = new Map<string, number>();
+  const items: string[] = [];
+  for (const heading of headings) {
+    const {text, explicitId} = splitHeadingText(heading.text);
+    const baseAnchor = options.useExplicitIds && explicitId ? explicitId : toAnchor(text);
+    const count = anchors.get(baseAnchor) ?? 0;
+    anchors.set(baseAnchor, count + 1);
+    const anchor = count ? `${baseAnchor}-${count}` : baseAnchor;
+    if (heading.level < options.minLevel || heading.level > options.maxLevel || isExcluded(text, options.excludeHeadings)) continue;
+
+    const display = options.stripFormattingInToc ? stripFormatting(text) : resolveLinksAndImages(text);
+    const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, Number(options.indentSize)));
+    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? items.length + 1 : 1}.` : options.bulletMarker;
+    items.push(`${indentation}${marker} [${display}](#${anchor})`);
+  }
+  return items;
+}
+
+function splitHeadingText(text: string): {text: string, explicitId: string | null} {
+  const withoutClosingHashes = text.trim().replace(/\\s+#+\\s*$/, '').trim();
+  const match = withoutClosingHashes.match(/\\s*\\{#([^}]+)\\}\\s*$/);
+  return match ? {text: withoutClosingHashes.slice(0, match.index).trim(), explicitId: match[1]} : {text: withoutClosingHashes, explicitId: null};
+}
+
+function resolveLinksAndImages(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_, target: string, label: string) => label ?? target)
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return resolveLinksAndImages(text)
+      .replace(/<[^>]*>/g, '')
+      .replace(/(\\*\\*|__|~~|`|\\*|_)/g, '');
+}
+
+function toAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  return exclusions.some((exclusion) => {
+    const regex = exclusion.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(text);
+      } catch (_) {
+        return text.toLowerCase() === exclusion.toLowerCase();
+      }
+    }
+    return text.toLowerCase() === exclusion.toLowerCase();
+  });
+}
